// Synthesis Staging · Fase 3 · spec 5-fases CC#4 2026-06-09
// Consolida en memoria: agent output + Apify results → staging_package
// NO hace INSERT/UPDATE a ninguna tabla.

const discoveryItem = $('Confirm barato · competitor list').first().json;
const apifyAggregate = $('[APIFY-WIRE] Aggregate Service responses (onboarding_e2e)').first().json;
const dealData = $('Validate Deal Data').first().json;

const discoveryPkg = discoveryItem.discovery_package || {};
const apifyResults = apifyAggregate.results || apifyAggregate.apify_results || [];

// brand_book_draft: conclusiones del agente + evidencia Apify
const brandBookDraft = {
  competitive_landscape: discoveryPkg.discovery_summary || "",
  competitors: discoveryPkg.competitors || [],
  icp_signals: discoveryPkg.icp_signals || [],
  own_handles: discoveryPkg.own_handles || {},
  apify_evidence_count: apifyResults.length,
  draft_status: "pre_gate",
  source_agent: "onboarding-specialist",
  source_apify: "discovery_e2e_scrapes",
  generated_at: new Date().toISOString()
};

// icp_draft: señales ICP identificadas
const icpSignals = discoveryPkg.icp_signals || [];
const icpDraft = {
  segments: icpSignals,
  primary_segment: icpSignals[0] || null,
  segment_count: icpSignals.length,
  draft_status: "pre_gate"
};

// competitive_analysis_draft
const competitiveAnalysisDraft = {
  competitors: discoveryPkg.competitors || [],
  scrape_targets_count: discoveryPkg.scrape_targets ? discoveryPkg.scrape_targets.length : 0,
  apify_results: apifyResults,
  landscape_summary: discoveryPkg.discovery_summary || "",
  draft_status: "pre_gate"
};

const stagingPackage = {
  brand_book_draft: brandBookDraft,
  icp_draft: icpDraft,
  competitive_analysis_draft: competitiveAnalysisDraft,
  evidence_sources: ["onboarding-specialist", "apify"],
  staging_timestamp: new Date().toISOString()
};

return [{
  json: {
    client_id: dealData.client_id,
    client_name: dealData.client_name,
    _journey_id: dealData._journey_id,
    staging_package: stagingPackage,
    competitor_count: (discoveryPkg.competitors || []).length,
    scrape_target_count: (discoveryPkg.scrape_targets || []).length
  }
}];

// Persist Canon · Fase 5 · solo tras PASS Camino III
// Escribe brand_book, ICP, análisis competitivo via API.
// RECIÉN AQUÍ se persisten los datos canonizados.

const stagingPkg = $json.staging_package || {};
const clientId = $('Validate Deal Data').first().json.client_id;
const apiUrl = $env.ZERO_RISK_API_URL || 'https://zero-risk-platform.vercel.app';
const apiKey = $env.INTERNAL_API_KEY;

const headers = {
  'Content-Type': 'application/json',
  'x-api-key': apiKey
};

// 1. POST brand_book
let brandBookResult = null;
try {
  const bbResp = await fetch(apiUrl + '/api/clients/' + clientId + '/brand-book', {
    method: 'POST',
    headers: headers,
    body: JSON.stringify({
      brand_book: stagingPkg.brand_book_draft,
      source: 'onboarding_e2e_5phase',
      camino_iii_approved: true,
      approved_at: new Date().toISOString()
    })
  });
  brandBookResult = { status: bbResp.status, ok: bbResp.ok };
} catch(e) {
  brandBookResult = { status: 'error', message: e.message };
}

// 2. POST ICP
let icpResult = null;
try {
  const icpResp = await fetch(apiUrl + '/api/clients/' + clientId + '/icp', {
    method: 'POST',
    headers: headers,
    body: JSON.stringify({
      icp: stagingPkg.icp_draft,
      source: 'onboarding_e2e_5phase',
      camino_iii_approved: true
    })
  });
  icpResult = { status: icpResp.status, ok: icpResp.ok };
} catch(e) {
  icpResult = { status: 'error', message: e.message };
}

// 3. POST competitive analysis al Brain como evidencia CANON (no provisional)
let brainResult = null;
try {
  const brainResp = await fetch(apiUrl + '/api/brain/ingest-source', {
    method: 'POST',
    headers: headers,
    body: JSON.stringify({
      client_id: clientId,
      source_type: 'competitive_intelligence',
      content: JSON.stringify(stagingPkg.competitive_analysis_draft),
      metadata: {
        provenance: 'onboarding_e2e_5phase_post_camino_iii',
        confidence: 'canon',
        type: 'evidencia_canon',
        camino_iii_approved: true,
        approved_at: new Date().toISOString()
      }
    })
  });
  brainResult = { status: brainResp.status, ok: brainResp.ok };
} catch(e) {
  brainResult = { status: 'error', message: e.message };
}

return [{
  json: {
    ...$json,
    persist_canon_results: {
      brand_book: brandBookResult,
      icp: icpResult,
      brain_canon: brainResult,
      persisted_at: new Date().toISOString()
    }
  }
}];

